import{_ as p,o as e,c as a,j as r,a as d,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"3.11.环境规则","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.11.环境规则.md","filePath":"1.基础规则/3.战斗规则/3.11.环境规则.md"}'),D={name:"1.基础规则/3.战斗规则/3.11.环境规则.md"};function C(n,b,s,o,_,l){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"_3-11-环境规则",tabindex:"-1"},[d("3.11.环境规则 "),r("a",{class:"header-anchor",href:"#_3-11-环境规则","aria-label":'Permalink to "3.11.环境规则"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),t('<h1 id="环境规则" tabindex="-1">环境规则 <a class="header-anchor" href="#环境规则" aria-label="Permalink to &quot;环境规则&quot;">​</a></h1><p>环境规则</p><p>此条规则的作用是模拟基于自然条件下对处于某一环境内的单位产生的影响，因此将环境根据支线等级进行区分。这一规则下的所有效应来源均为环境来源。</p><p>注：虽然环境效果会直接对区域内所有单位生效，但除非这一区域是天然存在的，否则一类环境在形成时一定会有至少一轮的时间给区域内的单位进行应对。</p><p>光照等级<br> 光亮条件分为4个等级：明亮、正常、昏暗、黑暗</p><p>明亮<br> 明亮光照的最典型情况为正午时分的沙漠。<br> 任何单位在以视觉定位的方式对处于明亮光照等级下的单位进行侦测检定时，获得3dp环境加值。<br> 处于明亮光照等级下的单位进行隐秘检定时，受到3dp环境减值。<br> 当他人试图以视觉侦查敏感范围以外的一片明亮光照环境下的具体情况时，所需承受的侦查检定成功数减值减少3点。<br> 本环境效果来源为D级环境来源。</p><p>常光<br> 典型情况为白天、灯火通明的城市、天气条件较好的具有满月夜晚。<br> 一个火把、手电、灯泡可使黑暗、昏暗环境下的20米圆形/锥形范围处于常光条件。<br> 人物在这一光照条件下可正常视物。</p><p>昏暗<br> 典型情况为月亮暗淡的夜晚。<br> 人物在这一光照环境下视觉受限。<br> 处于昏暗光照条件下的受影响单位以视觉侦测方式进行定位时，敏感范围缩减30米。<br> 不处于昏暗光照条件下，但受昏暗光照条件影响的单位至多以视觉侦测方式获取处于昏暗光照条件下单位的模糊定位。<br> 本环境效果来源为D级环境来源。</p><p>黑暗<br> 乌云密布的夜晚、山洞、地下矿洞、密闭房间等。<br> 处于这一环境下的受影响单位无法以视觉进行侦测，如同目盲。<br> 不处于黑暗光照条件下，但受黑暗光照条件影响的单位无法获得处于黑暗环境下单位的定位信息。<br> 本环境效果来源为C级环境来源。<br> 特殊的，若一个单位免疫D级环境来源或者具有昏暗视觉，则黑暗光照条件对其造成的效果等同于昏暗光照条件。</p><p>环境大致分为以下类别：地形、天气、特殊。</p><p>地形环境<br> 会对角色造成影响的地形环境大致有：森林、山地、冰原、沼泽、沙地、水中/河流。<br> 地形环境的区分较为明确，通常一个场景内不会有较大的改变。因此地形环境往往只能生效一种。</p><p>天气环境<br> 天气环境与地形不同，其分界并不清晰，一个天气往往是多种因素综合而成的产物。因此天气环境的构成要素往往是共同生效的。<br> 构成天气环境的因素大致有：雨、风、雾、冰雪等</p><p>特殊环境<br> 这是一些难以用地形/天气区分的环境类型，其包括太空环境、火山环境、有毒环境、易燃环境、地震、龙卷、漩涡、山崩。</p><p>地形环境</p><p>冰原<br> 冰原环境由于覆盖着大量的冰雪、冻土导致这一环境可能对角色产生阻碍。<br> 处于冰原环境影响下的单位在移动时，需要进行一个DC为2的平衡检定，失败则会倒地。角色可以将自身移动速度减半以避免这一检定。<br> 本环境效应的支线等级为无支线。</p><p>森林<br> 森林环境一般越靠近森林内部，树木的密集程度就越高。<br> 森林环境根据植被稀疏程度分为：疏林、丛林、密林</p><p>疏林<br> 处于此类环境外的单位对处于此类环境下的单位进行的远程攻击需承受2dp环境减值。<br> 受影响单位在这类环境下进行的远程攻击受到2dp环境减值。<br> 本环境效应的支线等级为无支线。</p><p>丛林<br> 处于此类环境外的单位对处于此类环境下的单位进行的远程攻击、洞察检定需承受3dp环境减值。<br> 受影响单位在这类环境下进行的远程攻击需承受3dp环境减值。<br> 在这类环境下进行移动需进行一个平衡检定，DC为2，失败则会陷入倒地。<br> 在这类环境进行主动掩蔽时可以获得大量掩蔽的加值。<br> 受到这类环境影响的单位无法进行直线冲锋。<br> 本环境效应的支线等级为D级。</p><p>密林<br> 处于此类环境外的单位对处于此类环境下的单位进行的远程攻击、洞察检定需承受6dp环境减值。<br> 受影响单位在这类环境下进行的远程攻击、洞察检定需承受6dp环境减值。<br> 在这类环境下进行移动需进行一个平衡检定，DC为3，失败则会陷入倒地。<br> 在这类环境进行主动掩蔽时可以获得大量掩蔽的加值。<br> 受到这类环境影响的单位无法进行直线冲锋。<br> 本环境效应的支线等级为C级。</p><p>山地<br> 山地可能与多种地形的混合作用，一个山坡上可能具有森林、雪地、河流等其他地形因素。<br> 山地地形可分为缓坡、陡坡、悬崖。</p><p>缓坡<br> 受此环境影响的单位在往高处移动时移动速度减少5米，在往低处移动时移动速度增加5米。<br> 本环境效应的支线等级为无支线。</p><p>陡坡<br> 受此环境影响的单位在往高处移动时移动速度减少10米，在往低处移动时移动速度增加10米。<br> 在此地形进行移动或受到伤害时，需要进行一个平衡检定，DC为3，失败则倒地并开始坠落，其高度为坠落处直到陡坡地形结束，将坠落伤害减半计算。<br> 本环境效应的支线等级为D级。</p><p>悬崖<br> 此地形只能以攀爬方式向上方进行移动。<br> 受影响单位在此地形进行移动或受到伤害时，需要进行一个平衡检定，DC为5，失败则倒地并开始坠落，其高度为坠落处直到悬崖地形结束。<br> 本环境效应的支线等级为D级。<br> 注：免疫环境效果无法令你不攀爬也能往上移动，而是令你在受到伤害/移动时无须进行平衡检定也不会跌落。</p><p>沼泽<br> 沼泽地形视其湿度可分为淖地、沼地、吃人沼泽。</p><p>淖地<br> 泥淖地形的地面泥浆较多，但地面硬度足够支撑人物正常行走。<br> 处于这一环境下的受影响单位移动速度减少5米，运动/敏捷检定受到2dp环境减值。</p><p>本效应的环境来源等级为无支线。</p><p>沼地<br> 沼地环境下，人物很难进行正常移动。<br> 处于这一环境下的受影响单位会陷入D级困难地形状态。<br> 受影响单位进行的运动/敏捷检定受到4dp环境减值。<br> 本效应的环境等级来源为D级。</p><p>吃人沼泽<br> 这一地形会令不及时脱身的单位受到生命危险。吃人沼泽与通常的湿地、沼地较为相似，在进入这一地区时，你可能需要以感知+生存+专业：求生进行DC为3的检定以分辨。<br> 处于本环境下的受影响单位会陷入困难地形状态。受影响单位在进行移动时，需要进行一个DC为6的反射检定，若失败则受到1点不可豁免的纠缠点数。<br> 受影响单位每在此环境下停留一轮，其身体就有等同1体积的部分下陷至沼泽内；每下陷1点体积，受影响单位进行的反射检定DC就提升1点。<br> 若单位身体的所有体积完全下馅至沼泽内，其会陷入窒息状态。此时若想要进行移动，需要先通过一个成功的游泳检定。<br> 若吃人沼泽内具有借力点（他人投掷的绳索、大型树木等），则受影响单位可借此避免下陷，并以1/4的移动速度在沼泽内移动。</p><p>本效应的环境等级来源为C级。</p><p>沙漠<br> 沙漠环境包含的要素大致有：沙地、流沙、沙丘</p><p>沙丘：类同山地环境的缓坡</p><p>沙地：长时间行走可能会有不适，但正常条件下几乎无影响。</p><p>流沙：类同吃人沼泽。</p><p>水中/河流环境<br> 当人物处于没过其体积1/5的液态环境时，即可将其判定为处于水中环境。</p><p>水中环境<br> 处于这一环境下的受影响单位会陷入同环境等级的困难地形状态。<br> 当水深超过受影响单位体积的2/5时，受影响单位可以通过游泳以避免困难地形的效果。<br> 若水面没过受影响单位的头顶（通常而言，这是因为其游泳检定失败或者水中环境是一个封闭的区域），其还会受到缺氧环境的影响。<br> 没有贯穿或超级贯穿特性的远程攻击，在入水后每1米视同经过了10米一般计算射程上限。<br> 造成雷电伤害的攻击如果落入水中环境，会将攻击扩散至落点周围10米内的所有单位。<br> 本效应的环境等级来源为D级。</p><p>河流环境<br> 通常而言，处于河流环境下的单位会如同处于水中环境一般受到影响，但有如下不同：<br> 处于河流环境下的受影响单位每轮都需要进行游泳检定，若失败则会沉至水下。进行的游泳检定DC会提升1～3点（小/中/大型河流）。<br> 受影响单位每轮都会被迫往河流流动方向移动5/15/25米。<br> 本效应的环境等级来源为C级。</p><p>杂项<br> 这是一些可能存在于多种环境下的地形，其环境效应来源均为无支线等级。</p><p>灌木丛：受到这类环境影响下的单位会陷入无支线级别的困难地形状态。蹲伏在这类环境下的单位可获得部分遮蔽。</p><p>荆棘：受到这类环境影响的单位会陷入无支线级别困难地形状态，在移动经过此类环境时，需要进行一个DC为2的反射/强韧豁免，失败则会承受1点流血异常点数。蹲伏在这类环境下的单位可获得部分遮蔽。</p><p>碎石堆：受到这类环境影响的单位移动速度降低10米，若单位在这类环境下倒地，则会受到1点额外的穿刺伤害。</p><p>湿地：受到这类环境影响的单位在全速移动时，需进行一个DC为2的平衡检定，若失败则会陷入倒地状态。</p><p>缺氧环境：此类环境的氧气含量缺失，这可能是多种因素造成的（如高海拔、燃烧、洞穴深处等）。<br> 受影响单位在这类环境下每轮需要进行一个DC为5的强韧豁免，若失败则受到1点不可豁免的冲击点数。</p><p>炎热环境：此类环境温度较高，这可能由于天气、地理位置等因素造成。<br> 受影响单位在这类环境下每连续活动1小时，就需要进行一个强韧豁免，DC为3，失败则承受差值点疲乏点数。<br> 环境温度每高于30摄氏度10点，此DC就提升1点。<br> 注：这一效应不考虑过于极端的炎热环境。</p><p>寒冷环境：此类环境温度较低，这可能由于天气、地理位置等因素造成。<br> 受影响单位在这类环境下每连续活动1小时，就需要进行一个强韧豁免，DC为3，失败则承受差值点肢体残障点数，作用于每一个肢体。<br> 环境温度每低于10摄氏度10度，此DC就提升1点。<br> 注：这一效应不考虑过于极端的寒冷环境。</p><p>天气环境</p><p>注：建筑、载具、树木等障碍物可能会阻碍天气环境生效。</p><p>雨<br> 具有细雨、中雨、暴雨三种类型。</p><p>细雨<br> 这一环境几乎不会对人产生影响。</p><p>大雨<br> 这一环境往往会令环境区域内的所有事物被雨水所侵润。<br> 处于这一环境下的所有受影响单位具有【电易伤1】、【火焰伤害抗力1】。<br> 受影响单位以视觉进行的侦测检定受到3dp环境减值。<br> 本效应的环境来源等级为D级。</p><p>特大暴雨<br> 倾盆大雨所带来的不仅是环境区域内的所有事物被雨水所淋湿，还会一定程度的影响到听觉与视觉。<br> 处于这一环境下的所有受影响单位额外具有【电易伤1】、【火焰伤害抗力1】。<br> 在这一环境内，受影响单位以视觉、听觉进行侦测的行为受到6dp环境减值，以视觉、听觉进行侦测定位时敏感范围下降30米。<br> 本效应的环境来源等级为C级。</p><p>风<br> 受到风环境影响的单位，其弹道学专业在计入检定时等级下降1/3/5级。（无支线1、D3、C5）</p><p>大风<br> 受影响单位处于顺风向情况下进行远程攻击时，其射程提升10米。<br> 受影响单位不处于顺风向情况下进行远程攻击时，其射程减少10米。<br> 受影响单位在环境区域内以嗅觉进行侦测时，敏感范围提升20米，但受到1dp环境减值。<br> 受影响单位在环境区域内以听觉进行侦测时，敏感范围提升20米，但受到1dp环境减值。<br> 本效应的环境来源等级为无支线。</p><p>狂风<br> 受影响单位处于顺风向情况下进行远程攻击时，其射程提升20米。<br> 受影响单位不处于顺风向情况下进行远程攻击时，其射程减少20米。<br> 受影响单位在环境区域内以嗅觉进行侦测时，敏感范围提升40米，但受到3dp环境减值。<br> 受影响单位在环境区域内以听觉进行侦测时，敏感范围提升40米，但受到3dp环境减值。<br> 本效应的环境来源等级为D级。</p><p>飓风/台风<br> 十二级及以上的风力环境。<br> 受影响单位在环境区域内进行远程攻击时，射程减少一半。<br> 环境区域外受影响单位发出的远程攻击经过环境区域计算的距离翻倍。（如：一个不免疫C级环境单位发出的远程攻击在经过范围40米的飓风区域时，按80米计算射程距离。）<br> 受影响单位在环境区域内以嗅觉、听觉进行侦测时，敏感范围提升一半，但受到6dp环境减值。<br> 受影响单位在环境区域内进行的运动检定受到6dp环境减值。<br> 十二级以上的每级风力会令本环境的所有减值增加1点。</p><p>本效应的环境来源等级为C级。</p><p>雾<br> 这一环境会严重影响人物的视觉可见范围。</p><p>薄雾<br> 受影响单位处于区域内会减少25米视觉感知范围。<br> 区域外的受影响单位对环境区域的视觉感知范围减少25米。<br> 本效应的环境来源等级为无支线级。<br> 大雾<br> 受影响单位处于区域内会减少50米视力感知范围至多减少至15米，进行的视觉侦测检定受到3dp环境减值。<br> 区域外的受影响单位对环境区域的视觉感知范围减少50米，进行的视觉侦测检定受到3dp环境减值。<br> 本效应的环境来源等级为D级。<br> 浓雾<br> 受影响单位处于区域内会减少100米视力感知范围至多减少至5米，进行的视觉侦测检定受到6dp环境减值。<br> 区域外的受影响单位对环境区域的视觉感知范围减少100米，进行的视觉侦测检定受到6dp环境减值。<br> 本效应的环境来源等级为C级。</p><p>雪<br> 这一环境会导致人物视觉受限，并可能结合寒冷环境、冰原地形因素影响。</p><p>细雪<br> 受影响单位处于区域内会减少10米视觉感知范围。<br> 区域外的受影响单位对环境区域的视觉感知范围减少10米。<br> 本效应的环境来源等级为无支线级。</p><p>大雪<br> 受影响单位处于区域内会减少25米视觉感知范围。<br> 区域外的受影响单位对环境区域的视觉感知范围减少25米。<br> 受影响单位身上的燃烧点数每轮会降低1点。<br> 受影响单位具有【冻寒能量易伤1】<br> 本效应的环境来源等级为D级。</p><p>暴雪<br> 受影响单位处于区域内会减少50米视觉感知范围。<br> 区域外的受影响单位对环境区域的视觉感知范围减少50米。<br> 受影响单位身上的燃烧点数每轮会降低1点。<br> 受影响单位具有【冻寒能量易伤2】<br> 本效应的环境来源等级为C级。</p><p>冰雹<br> 受影响单位初次进入该区域/在区域内结束回合时进行一个机运骰，若结果在5及以下，则需要进行一个DC为7的反射豁免，失败则受到差额的钝击伤害。<br> 本效应的环境来源等级为D级。</p><p>特殊环境</p><p>无氧环境<br> 此类环境中无任何氧气存在，这对于大部分生物而言是致命的。<br> 处于此类环境下的单位每轮需要进行一个DC为6的强韧豁免，若失败则承受1点不可豁免的严重伤害。这一严重伤害直到你重新吸入氧气前都无法被任何治疗效果所恢复。<br> 受影响单位每处于无氧环境一分钟，所进行的强韧豁免DC就提升1点。<br> 自然的，如果一个单位不需要氧气便可生存，其也不会受到无氧环境影响。<br> 本效应的环境来源等级为C级。</p><p>有毒环境<br> 此类环境可能由于有毒气体、腐蚀性液体、辐射因素导致。<br> 处于这一环境内的受影响单位每轮需要进行一个DC为10的强韧豁免，若失败则受到1点毒素/辐射严重伤害。<br> 受到伤害的单位可能会因为毒素而产生继发的不良影响。<br> 本效应的环境来源等级为C级。</p><p>易燃环境<br> 此环境内充斥着许多易燃因素，可能因为一个不善的处理就引发激烈的爆炸。<br> 易燃环境在通常情况下不会对场景内的单位产生影响。<br> 易燃环境会具有一个引发燃烧此环境的条件，当满足这一条件以后，易燃环境会产生爆炸，环境内的受影响单位需要进行反射豁免，DC为10，失败则受到差额穿刺物理（或其他类型）严重伤害。<br> 这之后，处于环境内的单位每轮都需要进行一个DC为8的强韧豁免，失败会再受到1点火焰严重伤害。<br> 本效应的环境来源等级为C级。</p><p>太空<br> 太空对于通常生物而言是极其致命的环境，一般生物根本无法在其中生存。太空中的致命要素有低温、无氧、辐射等因素导致。<br> 受到环境影响的单位每分钟都需要进行一个DC为19的强韧豁免检定，若失败则受到1点耐力属性伤害。每在此环境滞留一个小时，强韧豁免的DC就提升1点。<br> 此外，太空环境区域还可能伴有失重（见异常状态）、无氧环境等。<br> 本效应的环境来源等级为B级。</p><p>火山<br> 火山环境具有以下几个独特要素：熔岩区域、喷发火山</p><p>熔岩区域<br> 熔岩区域是一个C级困难地形。<br> 熔岩区域内具有大量的岩浆河流。<br> 直接触碰岩浆的受影响单位需要进行一个DC为13的强韧豁免，失败则受到差值的火焰严重伤害。<br> 当一个单位处于熔岩环境内结束自身回合时，其需要进行一次强韧豁免，DC为18，失败则受到差值的火焰严重伤害。<br> 如果一个单位处于熔岩环境内且其主动或者被动的向岩浆的下方进行位移，则其需要进行游泳检定，DC为10（或更高），若游泳检定失败，则会浸没在岩浆内，其每轮会受到6点不可豁免的火焰严重伤害。<br> 本效应的环境来源等级为B级。</p><p>喷发火山<br> 喷发火山会形成大量的熔岩区域，且在喷发时对区域内造成的影响等同等级8，震源深度为0的地震。<br> 本效应的环境来源等级为A级。</p><p>地震<br> 此类环境是由于地壳运动导致的，区域内与地面相连的所有建筑、单位都会受到相当剧烈的震动影响。<br> 在地震环境下所有的单位都会陷入困难地形状态。<br> 区域内的单位每轮都需要进行一个DC为12的平衡检定，失败则会倒地。<br> 区域内的所有单位每轮都会受到6点音波/力场伤害，强韧豁免。<br> 区域内的固定物体、建筑每轮都会受到6点无法豁免的音波/力场伤害。<br> 地震的烈度与两方面因素有关：震源深度、地震级数<br> 震源深度每有1公里，地震环境区域所造成的伤害、平衡检定的DC值就会下降1点。<br> 地震级数减去6级后，每剩余1级地震级数，地震所造成的伤害值、平衡检定的DC值就会提升8点。<br> 若地震的震源深度在地面3公里（可能更深）以下，则地震的环境效果只会影响与地面有直接接触的单位。<br> 震源深度为0千米、地震级数为6的地震效应的环境来源等级为B级。<br> 震源深度为0千米、地震级数为8的地震效应的环境来源等级为A级。</p><p>黑洞：黑洞引力井的捕捉范围内，一切事物都无法避免地坍缩至无穷小的质点。<br> 黑洞视界之内，宇宙演变周期在你眼中飞逝而过，从最初的大爆炸、物质云的积聚、恒星的诞生与衰老直至宇宙热寂……<br> 进入此区域后，区域内的所有单位每轮都需要进行一个DC为33的强韧豁免，失败则立即死亡。这是一个S级环境来源的即死效果。这一DC值可能更高或更低。<br> 所有单位在区域内皆处于S级困难地形影响下，且失去任何形式的感知方式，敏感范围视为0。<br> 本效应的环境来源等级为S级。</p><p>绝对零度：热力学的理论最低点，绝对无法通过有限次序步骤抵达的温度。<br> 所有物质的基本粒子在绝对零度时将停止运动，这一环境内时空的熵被锚定在不可撼动的绝对零点。<br> 处于绝对零度区域内的所有单位都会陷入时间停止状态。<br> 本效应的环境来源等级为S级。</p><hr><p>Copyright © 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',75)])])}const h=p(D,[["render",C]]);export{c as __pageData,h as default};
